import{_ as s,o as n,c as e,ae as t}from"./chunks/framework.EHGTsUvI.js";const _=JSON.parse('{"title":"架构设计：基于 VitePress 的博客与教程系统","description":"","frontmatter":{},"headers":[],"relativePath":"20260317-001-VitePress站点设计.md","filePath":"20260317-001-VitePress站点设计.md"}'),i={name:"20260317-001-VitePress站点设计.md"};function l(p,a,r,o,c,d){return n(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="架构设计-基于-vitepress-的博客与教程系统" tabindex="-1">架构设计：基于 VitePress 的博客与教程系统 <a class="header-anchor" href="#架构设计-基于-vitepress-的博客与教程系统" aria-label="Permalink to &quot;架构设计：基于 VitePress 的博客与教程系统&quot;">​</a></h1><h2 id="_1-目标" tabindex="-1">1. 目标 <a class="header-anchor" href="#_1-目标" aria-label="Permalink to &quot;1. 目标&quot;">​</a></h2><p>搭建一个高性能的、以 Markdown 驱动的纯静态网站，提供“基础教程”和“近期文章”（博客）两种不同心智体系的阅读体验。</p><h2 id="_2-技术栈" tabindex="-1">2. 技术栈 <a class="header-anchor" href="#_2-技术栈" aria-label="Permalink to &quot;2. 技术栈&quot;">​</a></h2><ul><li><strong>核心框架</strong>：VitePress (由 Vue 团队主导，基于 Vite 构建)</li><li><strong>文档编写</strong>：Markdown / MDX</li><li><strong>包管理器</strong>：Yarn</li><li><strong>语言</strong>：TypeScript (配置文件)</li></ul><h2 id="_3-目录结构设计" tabindex="-1">3. 目录结构设计 <a class="header-anchor" href="#_3-目录结构设计" aria-label="Permalink to &quot;3. 目录结构设计&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.</span></span>
<span class="line"><span>├── docs/                # 文档源文件目录</span></span>
<span class="line"><span>│   ├── .vitepress/      # VitePress 配置目录</span></span>
<span class="line"><span>│   │   └── config.mts   # 核心配置文件</span></span>
<span class="line"><span>│   ├── blog/            # 博客分类文章</span></span>
<span class="line"><span>│   │   ├── index.md     # 博客首页</span></span>
<span class="line"><span>│   │   ├── ...          # 具体博文</span></span>
<span class="line"><span>│   ├── tutorial/        # 教程分类文章</span></span>
<span class="line"><span>│   │   ├── index.md     # 教程首页</span></span>
<span class="line"><span>│   │   ├── ...          # 具体教程</span></span>
<span class="line"><span>│   └── index.md         # 站点首页</span></span>
<span class="line"><span>├── package.json         # 项目依赖与脚本配置</span></span>
<span class="line"><span>└── CHANGELOG.md         # 变更记录</span></span></code></pre></div><h2 id="_4-路由与侧边栏划分" tabindex="-1">4. 路由与侧边栏划分 <a class="header-anchor" href="#_4-路由与侧边栏划分" aria-label="Permalink to &quot;4. 路由与侧边栏划分&quot;">​</a></h2><ul><li><code>/tutorial/</code> 路径下的页面，侧边栏将呈现体系化的树形结构，方便读者一步步学习。</li><li><code>/blog/</code> 路径下的页面，侧边栏作为近期文章列表或时间轴使用。</li></ul><h2 id="_5-部署方案" tabindex="-1">5. 部署方案 <a class="header-anchor" href="#_5-部署方案" aria-label="Permalink to &quot;5. 部署方案&quot;">​</a></h2><p>开发人员可以在本地运行 <code>yarn docs:dev</code> 进行预览。上线时通过 <code>yarn docs:build</code> 生成产物后静态托管。</p>`,11)])])}const u=s(i,[["render",l]]);export{_ as __pageData,u as default};
